def {{nama_fungsi}}(exc=None, context_lines={{context_lines}}):
    """Format exception with source code context around error lines.
    If exc is None, uses sys.exc_info() current exception.
    Returns formatted string.
    """
    import sys
    if exc is None:
        exc_info = sys.exc_info()
        if exc_info[0] is None:
            return '(no active exception)'
        tb_lines = traceback.format_exception(*exc_info)
    elif isinstance(exc, BaseException):
        tb_lines = traceback.format_exception(type(exc), exc, exc.__traceback__)
    else:
        return str(exc)
    output = []
    for line in tb_lines:
        output.append(line.rstrip())
        for part in line.split('\n'):
            stripped = part.strip()
            if stripped.startswith('File "') and ', line ' in stripped:
                try:
                    parts = stripped.split('", line ')
                    filepath = parts[0].replace('File "', '')
                    lineno = int(parts[1].split(',')[0])
                    for offset in range(-context_lines, context_lines + 1):
                        ln = lineno + offset
                        if ln < 1:
                            continue
                        src = linecache.getline(filepath, ln).rstrip()
                        if src:
                            marker = ' >>>' if offset == 0 else '    '
                            output.append(marker + str(ln).rjust(4) + ' | ' + src)
                except (ValueError, IndexError):
                    pass
    return '\n'.join(output)

class {{nama_class}}:
    """Context manager that logs entry/exit with timing.
    Usage: with debug_ctx('my_operation'): do_work()
    """
    def __init__(self, label='block', logger=None, verbose=True):
        self.label = label
        self.logger = logger or (lambda msg: sys.stderr.write(msg + '\n'))
        self.verbose = verbose
        self.elapsed = 0
        self.exception = None

    def __enter__(self):
        self._start = time.perf_counter()
        if self.verbose:
            self.logger('[ENTER] ' + self.label)
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.elapsed = time.perf_counter() - self._start
        if exc_type:
            self.exception = exc_val
            self.logger('[EXIT]  %s — FAILED after %.4fs: %s: %s' % (self.label, self.elapsed, exc_type.__name__, exc_val))
        else:
            if self.verbose:
                self.logger('[EXIT]  %s — OK (%.4fs)' % (self.label, self.elapsed))
        return False


def {{nama_decorator}}(logger=None):
    """Decorator that logs function entry, exit, duration, and exceptions.
    Usage: @debug_log or @debug_log(logger=my_logger)
    """
    log_fn = logger or (lambda msg: sys.stderr.write(msg + '\n'))

    def _decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            name = func.__qualname__
            start = time.perf_counter()
            log_fn('[CALL]  %s(args=%r, kwargs=%r)' % (name, args, kwargs))
            try:
                result = func(*args, **kwargs)
                elapsed = time.perf_counter() - start
                log_fn('[RET]   %s → %r (%.4fs)' % (name, result, elapsed))
                return result
            except Exception as exc:
                elapsed = time.perf_counter() - start
                log_fn('[ERR]   %s → %s: %s (%.4fs)' % (name, type(exc).__name__, exc, elapsed))
                raise
        return wrapper

    return _decorator

class {{exception_name}}(Exception):
    """Exception with added context information."""
    def __init__(self, message, original=None, context=None):
        self.original = original
        self.context = context or {}
        ctx_str = ', '.join('%s=%r' % (k, v) for k, v in self.context.items())
        full_msg = message
        if ctx_str:
            full_msg += ' [' + ctx_str + ']'
        if original:
            full_msg += ' (caused by %s: %s)' % (type(original).__name__, original)
        super().__init__(full_msg)


def {{nama_fungsi}}(message, context=None):
    """Re-raise current exception with added context. Use inside except block.
    Usage:
        try:
            risky_operation()
        except Exception:
            reraise_with_context('Failed during setup', context={'user_id': 42})
    """
    exc_info = sys.exc_info()
    if exc_info[0] is None:
        raise RuntimeError('reraise_with_context called outside except block')
    original = exc_info[1]
    raise {{exception_name}}(message, original=original, context=context) from original

def {{nama_decorator}}(message=None, version=None, replacement=None):
    """Deprecation decorator. Emits DeprecationWarning when function is called.
    Usage: @deprecated('Use new_func instead', replacement='new_func')
    """
    def decorator(func):
        msg = message or ('%s is deprecated' % func.__qualname__)
        if replacement:
            msg += '. Use %s instead' % replacement
        if version:
            msg += ' (since v%s)' % version

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            warnings.warn(msg, category=DeprecationWarning, stacklevel=2)
            return func(*args, **kwargs)

        wrapper.__deprecated__ = True
        wrapper.__deprecation_message__ = msg
        return wrapper
    return decorator


def deprecated_class(message=None, version=None, replacement=None):
    """Deprecation decorator for classes. Warns on instantiation."""
    def decorator(cls):
        msg = message or ('%s is deprecated' % cls.__name__)
        if replacement:
            msg += '. Use %s instead' % replacement
        if version:
            msg += ' (since v%s)' % version
        original_init = cls.__init__

        def new_init(self, *args, **kwargs):
            warnings.warn(msg, category=DeprecationWarning, stacklevel=2)
            original_init(self, *args, **kwargs)

        cls.__init__ = new_init
        cls.__deprecated__ = True
        return cls
    return decorator

def {{nama_decorator}}(max_retries={{max_retries}}, base_delay={{base_delay}}, max_delay=60, jitter=True, exceptions=(Exception,)):
    """Retry decorator with exponential backoff and optional jitter.
    delay = min(max_delay, base_delay * 2^attempt) + random_jitter
    Usage: @retry(max_retries=5, base_delay=2)
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            last_exc = None
            for attempt in range(max_retries + 1):
                try:
                    return func(*args, **kwargs)
                except exceptions as exc:
                    last_exc = exc
                    if attempt >= max_retries:
                        raise
                    delay = min(max_delay, base_delay * (2 ** attempt))
                    if jitter:
                        delay = delay * (0.5 + random.random())
                    time.sleep(delay)
            raise last_exc
        wrapper._retry_max = max_retries
        return wrapper
    return decorator

def {{nama_fungsi}}(obj, path, default=None, separator='.'):
    """Safely get nested attribute or dict key using dot notation.
    Usage: safe_getattr(obj, 'user.address.city', default='unknown')
    Works with both object attributes and dict keys.
    """
    keys = path.split(separator)
    current = obj
    for key in keys:
        try:
            if isinstance(current, dict):
                current = current[key]
            elif isinstance(current, (list, tuple)) and key.isdigit():
                current = current[int(key)]
            else:
                current = getattr(current, key)
        except (KeyError, IndexError, AttributeError, TypeError):
            return default
    return current


def {{nama_fungsi_set}}(obj, path, value, separator='.'):
    """Safely set nested attribute or dict key using dot notation.
    Creates intermediate dicts if they don't exist.
    Usage: safe_setattr(config, 'db.connection.host', 'localhost')
    """
    keys = path.split(separator)
    current = obj
    for key in keys[:-1]:
        if isinstance(current, dict):
            if key not in current or not isinstance(current[key], (dict,)):
                current[key] = {}
            current = current[key]
        else:
            try:
                current = getattr(current, key)
            except AttributeError:
                return False
    last_key = keys[-1]
    if isinstance(current, dict):
        current[last_key] = value
        return True
    try:
        setattr(current, last_key, value)
        return True
    except (AttributeError, TypeError):
        return False
